function pickProduct(tier, type) {
  const list = CATALOG[tier] || [];
  return list.find(p => p.type === type) || null;
}

// Standard amortizing loan monthly payment: P * [r(1+r)^n] / [(1+r)^n - 1]
// principal: total financed amount, annualRatePct: e.g. 9 for 9%, termYears: loan length
function calcMonthlyPayment(principal, annualRatePct, termYears) {
  const P = Number(principal) || 0;
  if (P <= 0) return 0;
  const r = (annualRatePct / 100) / 12;       // monthly rate
  const n = termYears * 12;                    // number of payments
  if (r === 0) return P / n;
  const factor = Math.pow(1 + r, n);
  return P * (r * factor) / (factor - 1);
}

// Build a system rec for ANY tier on demand — used when advisor manually swaps a tier
function buildAnyTierSystem(tier, noDucts) {
  const meta = TIER_META[tier];
  if (noDucts) {
    const ductless = pickProduct(tier, "ductless") || pickProduct(tier, "crossover");
    if (!ductless) return null;
    return buildSystemRec(tier, {
      name: ductless.name,
      reason: "Ductless system — no ductwork required",
      products: [ductless],
      tag: meta.label,
    });
  }
  const furnace = pickProduct(tier, "furnace");
  const ac      = pickProduct(tier, "ac");
  const hp      = pickProduct(tier, "heatpump");
  const crossover = pickProduct(tier, "crossover");
  const products = (hp || ac) ? [hp || ac, furnace].filter(Boolean) : [crossover, furnace].filter(Boolean);
  if (products.length === 0) return null;
  return buildSystemRec(tier, {
    name: hp ? "Heat Pump System" : crossover ? "Crossover Heat Pump System" : "Air Conditioner + Furnace System",
    reason: `A great fit at the ${meta.label} level — built to match what matters most to you.`,
    products,
    tag: meta.label,
  });
}

function buildSystemRec(tier, opts) {
  const meta = TIER_META[tier];
  const { name, reason, products, tag } = opts;
  return {
    tierLabel: meta.label,
    tierColor: meta.color,
    tierBg: meta.bg,
    tierIcon: meta.icon,
    name,
    reason,
    products,
    tag: tag || meta.label,
  };
}

function getRecommendations(answers) {
  const problems   = answers.problem   || [];
  const priorities = answers.priority  || [];
  const size       = answers.home_size?.[0];
  const existing   = answers.existing  || [];
  const budget     = answers.budget?.[0];
  const age        = answers.system_age?.[0];

  const noDucts         = existing.includes("no_ducts") || existing.includes("window_units") || existing.includes("wall_heater") || existing.includes("floor_heater");
  const hasMiniSplit    = existing.includes("mini_split");
  const hasHumidity     = problems.includes("humidity");
  const hasAirQuality   = problems.includes("air_quality") || problems.includes("environment");
  const wantsCarbon     = priorities.includes("carbon");
  const wantsEfficiency = priorities.includes("efficiency") || problems.includes("high_bills") || wantsCarbon;
  const wantsComfort    = priorities.includes("comfort")    || problems.includes("hot_rooms");
  const wantsSmart      = priorities.includes("smart")      || problems.includes("thermostat");
  const wantsQuiet      = priorities.includes("quiet");
  const wantsHealth     = priorities.includes("air")        || hasAirQuality || wantsCarbon;
  const bigHome         = ["2500_3500","over_3500"].includes(size);
  const highBudget      = budget === "best_available";
  const lowBudget       = budget === "cash_low";
  const midBudget       = budget === "best_balance" || budget === "lower_payments";
  const oldSystem       = ["aging","old"].includes(age);

  const recs = [];

  // ── No ducts / wall or floor heaters / window units → Ductless only ──
  if (noDucts || hasMiniSplit) {
    const ductless = pickProduct("bronze","ductless");
    recs.push(buildSystemRec("bronze", {
      name: ductless.name,
      reason: "No ductwork required — perfect fit since you don't have existing ducts",
      products: [ductless],
      tag: "Best Fit — No Ducts Needed",
    }));
    return { recs, addOns: buildAddOns({ hasAirQuality, hasHumidity, oldSystem }) };
  }

  // ── Efficiency or comfort priority → Lead with Platinum ──
  if (wantsEfficiency || wantsComfort) {
    const furnace = pickProduct("platinum","furnace");
    const ac      = wantsEfficiency ? pickProduct("platinum","ac") : null;
    const hp      = pickProduct("platinum","heatpump");
    // Prefer heat pump as the headline since it covers heating+cooling in one
    const primaryProducts = ac && wantsEfficiency
      ? [hp, furnace].filter(Boolean)
      : [hp, furnace].filter(Boolean);

    recs.push(buildSystemRec("platinum", {
      name: "Infinity Variable-Capacity Heat Pump System",
      reason: wantsEfficiency
        ? "Carrier's highest-efficiency system — the lowest possible utility bills"
        : "Carrier's top comfort system — the most consistent temperature in every room",
      products: primaryProducts,
      tag: wantsEfficiency ? "Most Efficient" : "Best Comfort",
    }));

    // Alternative: Gold tier
    const goldAc = pickProduct("gold","ac");
    const goldFurnace = pickProduct("gold","furnace");
    const goldHp = pickProduct("gold","heatpump");
    recs.push(buildSystemRec("gold", {
      name: "Performance Two-Stage System",
      reason: "A great step-down from Platinum — two-stage comfort at a more accessible price",
      products: [goldHp || goldAc, goldFurnace].filter(Boolean),
      tag: "Great Alternative",
    }));
  }

  // ── Value / cash preference → Bronze primary, Silver as upgrade ──
  else if (lowBudget || (!highBudget && !wantsEfficiency && !wantsComfort)) {
    const bronzeAc = pickProduct("bronze","ac");
    const bronzeFurnace = pickProduct("bronze","furnace");
    const bronzeHp = pickProduct("bronze","heatpump");
    recs.push(buildSystemRec("bronze", {
      name: "Comfort Series System",
      reason: "Dependable Carrier quality at the most accessible price point",
      products: [bronzeHp || bronzeAc, bronzeFurnace].filter(Boolean),
      tag: "Best Price",
    }));

    const silverAc = pickProduct("silver","ac");
    const silverFurnace = pickProduct("silver","furnace");
    const silverHp = pickProduct("silver","heatpump");
    recs.push(buildSystemRec("silver", {
      name: "Performance Single-Stage System",
      reason: "A modest upgrade from Bronze with improved efficiency and reliability",
      products: [silverHp || silverAc, silverFurnace].filter(Boolean),
      tag: "Upgrade Option",
    }));
  }

  // ── Default / balanced → Silver primary, Gold as upgrade ──
  else {
    const silverAc = pickProduct("silver","ac");
    const silverFurnace = pickProduct("silver","furnace");
    const silverHp = pickProduct("silver","heatpump");
    recs.push(buildSystemRec("silver", {
      name: "Performance Single-Stage System",
      reason: "Reliable Carrier performance with proven value for your home",
      products: [silverHp || silverAc, silverFurnace].filter(Boolean),
      tag: "Primary Recommendation",
    }));

    const goldAc = pickProduct("gold","ac");
    const goldFurnace = pickProduct("gold","furnace");
    const goldHp = pickProduct("gold","heatpump");
    recs.push(buildSystemRec("gold", {
      name: "Performance Two-Stage System",
      reason: "A worthwhile upgrade — two-stage operation for better comfort and efficiency",
      products: [goldHp || goldAc, goldFurnace].filter(Boolean),
      tag: "Great Alternative",
    }));
  }

  // ── Crossover always available as a flexible alternative (ducted homes) ──
  const crossoverHp = pickProduct("silver","crossover");
  const crossoverHandler = pickProduct("silver","handler");
  if (crossoverHp && bigHome === false && !recs.find(r => r.tag.includes("No Ducts"))) {
    // Only add if not already showing 2 recs to keep proposal at "2 — primary and one alternative"
  }

  return { recs, addOns: buildAddOns({ hasAirQuality, hasHumidity, oldSystem, wantsSmart }) };
}

function buildAddOns({ hasAirQuality, hasHumidity, oldSystem }) {
  return ACCESSORIES.filter(a => {
    if (a.showWhen === "always") return true;
    if (a.showWhen === "air_quality") return hasAirQuality;
    if (a.showWhen === "humidity") return hasHumidity;
    if (a.showWhen === "old_system") return oldSystem;
    return false;
  });
}

function groupAddOns(addOns) {
  const g = {};
  addOns.forEach(a => {
    if (!g[a.category]) g[a.category] = [];
    if (!g[a.category].find(x=>x.name===a.name)) g[a.category].push(a);
  });
  return g;
}

